def plot_validity(output, ground_truth):
    plot_output = output[0]
    has_words_output = output[1]
    has_words_ground_truth = ground_truth[1]

    if has_words_ground_truth:
        return isinstance(plot_output, plt.Axes) and has_words_output == has_words_ground_truth
    else:
        return plot_output is None and has_words_output == has_words_ground_truth

