def explained_variance_ratio_validity(output, ground_truth):
    output_var = {col: line.get_ydata() for col, line in zip(output[0].columns[:-1], output[1].get_lines())}  # Get explained variance from plot
    ground_truth_var = {col: line.get_ydata() for col, line in zip(ground_truth[0].columns[:-1], ground_truth[1].get_lines())}
    if set(output_var.keys()) != set(ground_truth_var.keys()):
        return False
    for key in output_var:
        if not np.allclose(output_var[key], ground_truth_var[key]):
            return False
    return True

