def mean_value_comparison(output, ground_truth):
    stats_df_output = output[0]  # extract the stats DataFrame from the output tuple
    stats_df_ground_truth = ground_truth[0]
    output_means = stats_df_output.loc['mean']
    ground_truth_means = stats_df_ground_truth.loc['mean']
    return max(0,1-((output_means - ground_truth_means).abs() / ground_truth_means).mean())

