def boxplot_comparison(output, ground_truth):
    import numpy as np
    boxplot_axes = output[1]  # extract the boxplot axes from tuple
    ground_truth_axes = ground_truth[1]
    comparison_results = [
        np.array_equal(o.get_path().vertices, g.get_path().vertices)
        for o, g in zip(boxplot_axes.patches, ground_truth_axes.patches)
    ]
    return all(comparison_results)

