                    [11, 23, 36, 180, 32, 98, 96, 56, 32, 72, 7, 24, 32],
                ]
            }
        )
        df.to_csv(self.f_5, index=False)

    def tearDown(self):
        import shutil
        try:
            shutil.rmtree(self.test_dir)
        except OSError as e:
            print(e)

    def test_case_1(self):
        df, plot = task_func(self.f_1)
