    def test_plot_labels(self):
        # Check the first subplot for appropriate labels as a proxy for the rest
        ax = self.fig.axes[0]
        self.assertIn('sepal length', ax.get_xlabel() + ax.get_ylabel(), "Axes labels should include feature names.")

