    # Check if all columns in the output DataFrame are present in the ground truth
    if not all(col in ground_truth_df.columns for col in output_df.columns):
        return False

    # Check the data types of the columns
    for col in output_df.columns:
        if output_df[col].dtype != ground_truth_df[col].dtype:
