import pandas as pd
import matplotlib.pyplot as plt

def task_func(df, dct, columns=None, plot_histograms=False):
    if not isinstance(df, pd.DataFrame):
        raise ValueError("Input must be a pandas DataFrame")

    replaced_df = df.replace(dct)

    hist_fig = None
    if plot_histograms and columns is not None:
        hist_fig, axes = plt.subplots(len(columns), 1, figsize=(8, 5 * len(columns)))
        if len(columns) == 1:
            axes = [axes]
        for ax, column in zip(axes, columns):
            if column in replaced_df.columns:
                replaced_df[column].hist(ax=ax)
                ax.set_title(f'Histogram of {column}')
                ax.set_xlabel(column)
                ax.set_ylabel('Frequency')
            else:
                ax.set_title(f'Column {column} does not exist in the DataFrame')
                ax.set_axis_off()

    return replaced_df, hist_fig

