import pandas as pd
from sklearn.preprocessing import StandardScaler

def task_func(df):
    if not all(col in df.columns for col in ['id', 'age', 'income']):
        raise ValueError("DataFrame must contain 'id', 'age', and 'income' columns.")

    scaler = StandardScaler()
    grouped = df.groupby('id')

    standardized_df = df.copy()
    for name, group in grouped:
        standardized_values = scaler.fit_transform(group[['age', 'income']])
        standardized_df.loc[group.index, ['age', 'income']] = standardized_values

    return (standardized_df,)

