import os
import pandas as pd
import re

def task_func(file_path: str) -> pd.DataFrame:
    if not os.path.isfile(file_path):
        raise FileNotFoundError(f"The specified log file does not exist: {file_path}")

    log_entries = []
    log_pattern = re.compile(r'(^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}\.\d{6}) - (\w+) - (.+)')

    with open(file_path, 'r') as file:
        for line in file:
            match = log_pattern.match(line)
            if match:
                timestamp, level, message = match.groups()
                log_entries.append({'Timestamp': timestamp, 'Level': level, 'Message': message})

    log_df = pd.DataFrame(log_entries, columns=['Timestamp', 'Level', 'Message'])
    return (log_df,)

