def mean_median_correctness(output, ground_truth):
    output_results = output[0]  # extract the results dictionary from tuple
    ground_truth_results = ground_truth[0]  # extract the ground truth results dictionary
    correctness_count = 0

    for key in output_results.keys():
        if (output_results[key]['mean'] == ground_truth_results[key]['mean']) and \
           (output_results[key]['median'] == ground_truth_results[key]['median']):
            correctness_count += 1

    return correctness_count / len(ground_truth_results)

