import numpy as np
import pandas as pd
from sklearn.linear_model import LinearRegression

def task_func(df, target_column, target_values=None):
    if not isinstance(df, pd.DataFrame):
        raise ValueError("df must be a DataFrame")
    if not isinstance(target_column, str):
        raise ValueError("target_column must be a string")
    if target_values is not None and not (isinstance(target_values, (list, np.ndarray))):
        raise ValueError("target_values must be array-like")

    # Replace elements not in target_values with zeros
    if target_values is not None:
        df[df.columns] = df[df.columns].where(df[df.columns].isin(target_values), 0)

    # Prepare data for linear regression
    X = df.drop(columns=[target_column])
    y = df[target_column]

    # Train linear regression model
    model = LinearRegression()
    model.fit(X, y)

    return (model,)

