import numpy as np
from scipy.stats import norm

def task_func(data: np.ndarray, threshold: float = 2.0) -> tuple:
    mean = np.mean(data)
    std_dev = np.std(data)

    if std_dev == 0:
        return [], mean, np.var(data)

    z_scores = (data - mean) / std_dev
    outliers = np.where(np.abs(z_scores) > threshold)[0].tolist()

    return outliers, mean, np.var(data)

