import pandas as pd
import numpy as np

def task_func(fruit_data):
    if not fruit_data:
        return (pd.DataFrame(columns=['Total Count', 'Average Count']),)

    fruit_count = {}

    for fruit, count in fruit_data:
        if fruit in fruit_count:
            fruit_count[fruit].append(count)
        else:
            fruit_count[fruit] = [count]

    results = {fruit: [sum(counts), np.mean(counts)] for fruit, counts in fruit_count.items()}

    df = pd.DataFrame.from_dict(results, orient='index', columns=['Total Count', 'Average Count'])
    return (df,)

