def task_func(d):
    counts = {
        'x': Counter(),
        'y': Counter(),
        'z': Counter()
    }

    for item in d:
        if 'x' in item:
            counts['x'][item['x']] += 1
        if 'y' in item:
            counts['y'][item['y']] += 1
        if 'z' in item:
            counts['z'][item['z']] += 1

