from sklearn.preprocessing import MinMaxScaler
import pandas as pd

def task_func(df: pd.DataFrame) -> pd.DataFrame:
    if df.empty:
        raise ValueError("The DataFrame is empty.")

    if df.isnull().values.any():
        raise ValueError("The DataFrame contains NaN values.")

    if not all(np.issubdtype(df[col].dtype, np.number) for col in df.columns):
        raise TypeError("The DataFrame contains non-numeric data types.")

    cumsum_df = df.cumsum()
    scaler = MinMaxScaler()
    normalized_cumsum = scaler.fit_transform(cumsum_df)

    normalized_cumsum_df = pd.DataFrame(normalized_cumsum, columns=cumsum_df.columns)

    return (normalized_cumsum_df,)

