def fitted_normal_distribution_accuracy(output, ground_truth):
    output_mu = output[1]  # extract mu from tuple
    output_std = output[2]  # extract std from tuple
    ground_truth_mu = ground_truth[1]
    ground_truth_std = ground_truth[2]
    return np.isclose(output_mu, ground_truth_mu, atol=1e-5) and np.isclose(output_std, ground_truth_std, atol=1e-5)

