def f1_score_specific_class(output, ground_truth, class_name='0'):
    from sklearn.metrics import f1_score
    # Extract the classification report from the output
    report = output[0].split('\n')
    for line in report:
        if class_name in line:
            f1_value_output = float(line.split()[4])  # Extract F1 Score for the specific class
            break
    # Extract the F1 Score from ground truth
    report_gt = ground_truth[0].split('\n')
    for line in report_gt:
        if class_name in line:
            f1_value_gt = float(line.split()[4])  # Extract F1 Score for the specific class in ground truth
            break
    return (f1_value_output - f1_value_gt)<0.01

