def row_sum_accuracy(output, ground_truth):
    output_df = output[0]
    ground_truth_df = ground_truth[0]
    ground_truth_sum = ground_truth_df['Row Sum'].tolist()
    for col_name in output_df.columns:
        if 'Sum' in col_name or 'sum' in col_name:
            output_sum = output_df[col_name].tolist()
            return np.allclose(ground_truth_sum, output_sum)
    return False

