def data_cleaning_accuracy(output, ground_truth):
    output_prices = output[0]['mean'], output[0]['median'], output[0]['std_dev']
    ground_truth_prices = ground_truth[0]['mean'], ground_truth[0]['median'], ground_truth[0]['std_dev']
    return all(np.isclose(a, b) for a, b in zip(output_prices, ground_truth_prices))

